    @Test
    void save_throws4612_whenDateInPast() {
        assertThatThrownBy(() -> service.saveAssignment(new SaveAssignmentCommand(
            101L, 201L, "day", LocalDate.now().minusDays(1), 301L)))
            .hasMessageContaining("4612");
    }

